"use client";

import { useState } from "react";
import { useConfig } from "@/context/ConfigContext";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Search, Download, Copy, RotateCcw, Eye } from "lucide-react";
import { GenericRenderer } from "@/components/editor/GenericRenderer";
import { CatalogEditor } from "@/components/editor/CatalogEditor";
import { MainGroupEditor } from "@/components/editor/MainGroupEditor";
import { OrderingEditor } from "@/components/editor/OrderingEditor";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from "@/components/ui/dialog";

export function MainEditor() {
    const { currentValues, fileName, exportConfig, resetAll } = useConfig();
    const [searchTerm, setSearchTerm] = useState("");

    const sections = [
        { id: "catalogs", title: "Catalogs", keys: ["selected_catalogs", "pinned_catalogs", "small_catalogs", "top_row_catalogs", "starred_catalogs", "randomized_catalogs", "small_toprow_catalogs", "catalog_ordering"] },
        { id: "ordering", title: "Ordering", keys: ["shelf_order", "main_group_order", "subgroup_order", "catalog_group_order", "stream_button_elements_order", "mdblist_rating_order"] },
        { id: "caches", title: "Caches", keys: ["catalog_cache_duration", "recommendation_cache_duration", "metadata_cache_duration", "image_cache_duration"] },
        { id: "patterns", title: "Patterns & Regex", keys: ["pattern_tag_enabled_patterns", "regex_pattern_custom_names", "regex_pattern_image_urls", "auto_play_patterns", "pattern_image_color_indices", "pattern_border_radius_indices", "pattern_default_filter_enabled_patterns", "pattern_background_opacities", "pattern_border_thickness_indices", "pattern_color_indices", "pattern_color_hex_values", "auto_play_enabled_patterns"] },
        { id: "player", title: "Player & Subtitles", keys: ["subtitle_font_size", "subtitle_italic", "preferred_audio_language", "preferred_subtitle_language", "isASSUseImageRender", "isSRTUseImageRender", "subtitle_bold", "subtitle_background_color", "subtitle_color", "hide_external_playback_prompt", "enable_external_player_trakt_scrobbling", "default_players", "intro_skip_times"] },
        { id: "general", title: "General Settings", keys: [] }, // Fallback for all other keys
    ];

    // Map keys to their section
    const keyToSectionMap = new Map<string, string>();
    sections.forEach(s => s.keys.forEach(k => keyToSectionMap.set(k, s.id)));

    const handleDownload = () => {
        const config = exportConfig();
        if (!config) return;

        const timestamp = new Date().toISOString().replace(/[:.]/g, "-").slice(0, 16);
        const newFileName = `omni-config-${timestamp}.json`;

        const blob = new Blob([JSON.stringify(config, null, 2)], { type: "application/json" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = newFileName;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    const handleCopy = () => {
        const config = exportConfig();
        if (!config) return;
        navigator.clipboard.writeText(JSON.stringify(config, null, 2));
        alert("Copied to clipboard!");
    };

    return (
        <div className="flex h-screen overflow-hidden bg-neutral-950 text-neutral-100 font-sans">
            {/* Sidebar */}
            <aside className="w-64 border-r border-neutral-800 bg-neutral-900 flex flex-col">
                <div className="p-4 border-b border-neutral-800">
                    <h1 className="text-xl font-bold flex items-center gap-2">
                        <span className="bg-blue-600 p-1.5 rounded text-white text-xs">O</span>
                        Omni Config
                    </h1>
                    <p className="text-xs text-neutral-500 mt-1 truncate">{fileName}</p>
                </div>

                <div className="p-4 border-b border-neutral-800 space-y-3">
                    <div className="relative">
                        <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-neutral-500" />
                        <Input
                            placeholder="Search settings..."
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                            className="pl-9 bg-neutral-950 border-neutral-800 text-sm h-9"
                        />
                    </div>
                </div>

                <nav className="flex-1 overflow-y-auto p-4 space-y-1">
                    {sections.map(section => (
                        <a
                            key={section.id}
                            href={`#${section.id}`}
                            className="block px-3 py-2 text-sm text-neutral-400 hover:text-neutral-100 hover:bg-neutral-800 rounded-md transition-colors"
                        >
                            {section.title}
                        </a>
                    ))}
                </nav>

                <div className="p-4 border-t border-neutral-800 space-y-2">

                    <Dialog>
                        <DialogTrigger asChild>
                            <Button variant="outline" className="w-full border-neutral-800 bg-neutral-900 hover:bg-neutral-800 h-9 text-neutral-300" size="sm">
                                <Eye className="w-4 h-4 mr-2" />
                                Raw JSON Preview
                            </Button>
                        </DialogTrigger>
                        <DialogContent className="max-w-3xl bg-neutral-950 border-neutral-800 text-neutral-100">
                            <DialogHeader>
                                <DialogTitle>Raw Export Output Preview</DialogTitle>
                            </DialogHeader>
                            <div className="bg-neutral-900 border border-neutral-800 rounded-md p-4 max-h-[60vh] overflow-y-auto font-mono text-xs text-neutral-300 whitespace-pre-wrap">
                                {JSON.stringify(exportConfig(), null, 2)}
                            </div>
                        </DialogContent>
                    </Dialog>

                    <Button onClick={handleDownload} className="w-full bg-blue-600 hover:bg-blue-700 h-9 shrink-0" size="sm">
                        <Download className="w-4 h-4 mr-2" />
                        Download JSON
                    </Button>
                    <Button onClick={handleCopy} variant="outline" className="w-full border-neutral-800 bg-transparent hover:bg-neutral-800 h-9 shrink-0" size="sm">
                        <Copy className="w-4 h-4 mr-2" />
                        Copy to Clipboard
                    </Button>
                </div>
            </aside>

            {/* Main Content */}
            <main className="flex-1 overflow-y-auto scroll-smooth">
                <div className="max-w-4xl mx-auto p-8 space-y-12">

                    <div className="flex items-center justify-between border-b border-neutral-800 pb-4">
                        <h2 className="text-2xl font-semibold">Configuration Editor</h2>
                        <Button variant="ghost" size="sm" className="text-neutral-400 hover:text-white" onClick={resetAll}>
                            <RotateCcw className="w-4 h-4 mr-2" />
                            Reset All Changes
                        </Button>
                    </div>

                    {sections.map(section => {
                        // Find keys that exist in current config for this section
                        const sectionKeys = section.keys.filter(k => currentValues[k] !== undefined);

                        // For general section, get all keys not in other sections
                        let keysToRender = sectionKeys;
                        if (section.id === "general") {
                            const assignedKeys = new Set(sections.flatMap(s => s.keys));
                            keysToRender = Object.keys(currentValues).filter(k => !assignedKeys.has(k) && currentValues[k] !== undefined);
                        }

                        if (keysToRender.length === 0 && section.id !== "catalogs") return null;

                        return (
                            <section key={section.id} id={section.id} className="scroll-mt-8">
                                <div className="flex items-center justify-between mb-6">
                                    <h3 className="text-xl font-medium text-neutral-200">{section.title}</h3>
                                    {section.id === "catalogs" && (
                                        <span className="text-xs px-2 py-1 bg-blue-500/10 text-blue-400 border border-blue-500/20 rounded">Bespoke UI</span>
                                    )}
                                </div>

                                <div className="space-y-4">
                                    {section.id === "catalogs" ? (
                                        <div className="space-y-12">
                                            <div>
                                                <h4 className="text-lg font-medium text-neutral-300 mb-4 border-b border-neutral-800 pb-2">Global Catalogs Ordering</h4>
                                                <CatalogEditor />
                                            </div>
                                            <div>
                                                <h4 className="text-lg font-medium text-neutral-300 mb-4 border-b border-neutral-800 pb-2">Main Catalog Groups</h4>
                                                <MainGroupEditor />
                                            </div>
                                        </div>
                                    ) : section.id === "ordering" ? (
                                        <div className="space-y-6">
                                            {keysToRender.map(key => (
                                                <OrderingEditor
                                                    key={key}
                                                    configKey={key}
                                                />
                                            ))}
                                        </div>
                                    ) : (
                                        <div className="space-y-6">
                                            {keysToRender.map(key => (
                                                <GenericRenderer
                                                    key={key}
                                                    data={currentValues[key]}
                                                    path={[key]}
                                                    searchQuery={searchTerm}
                                                />
                                            ))}
                                        </div>
                                    )}
                                </div>
                            </section>
                        );
                    })}

                </div>
            </main>
        </div>
    );
}
